/**
 * read-goal.ts
 * 读取 .ai/mcp/latest-goal.md 文件内容，提取其中的目标描述
 */

import * as fs from "fs";
import * as path from "path";

function resolveGoalFile(): string {
  const candidates = [
    path.join(process.cwd(), ".ai", "mcp", "latest-goal.md"),
    path.resolve(__dirname, ".ai", "mcp", "latest-goal.md"),
  ];

  for (const p of candidates) {
    if (fs.existsSync(p)) return p;
  }

  throw new Error(
    "未找到 .ai/mcp/latest-goal.md 文件。请确保在项目根目录下运行，或该文件存在。"
  );
}

function extractGoal(content: string): { title: string; sections: Record<string, string[]> } {
  const lines = content.split("\n");
  const title = lines[0].trim();
  const sections: Record<string, string[]> = {};

  let currentSection = "";
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];
    const headingMatch = line.match(/^\*\*(.+?)\*\*[:：]?\s*$/);

    if (headingMatch) {
      currentSection = headingMatch[1].replace(/\*\*/g, "");
      sections[currentSection] = [];
    } else if (line.trim().startsWith("-") && currentSection) {
      sections[currentSection].push(line.trim().replace(/^-\s*/, ""));
    } else if (line.trim().match(/^\d+\./) && currentSection) {
      sections[currentSection].push(line.trim());
    } else if (line.trim() && currentSection) {
      sections[currentSection].push(line.trim());
    }
  }

  return { title, sections };
}

function main(): void {
  const filePath = resolveGoalFile();
  const content = fs.readFileSync(filePath, "utf-8");
  const { title, sections } = extractGoal(content);

  const output = {
    source: filePath,
    title,
    sections,
    raw: content.trim(),
  };

  console.log(JSON.stringify(output, null, 2));
}

main();
